156→        return hashGalaxies.map(g => {
157→            const animated = galaxyPositions.get(g.userId);
158→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
159→        });
160→    }, [hashGalaxies, galaxyPositions]);
161→
162→    const getComputedStarPosition = useCallback((post) => {
163→        if (!post) return null;
164→
165→        const uid = post.users?.id ?? post.user_id;
166→        const hashGal = userHomeCoords(uid);
167→        const animGal = galaxyPositions.get(uid);
168→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
169→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
170→        const pull = starPullOffsets.get(post.id);
171→
172→        const baseX = post.universe_x ?? post.display_x;
173→        const baseY = post.universe_y ?? post.display_y;
174→        if (baseX == null || baseY == null) return null;
175→
176→        return {
177→            x: baseX + galDx + (pull?.dx ?? 0),
178→            y: baseY + galDy + (pull?.dy ?? 0),
179→        };
180→    }, [galaxyPositions, starPullOffsets]);
181→
182→    // Resolve logged-in user's galaxy target independently from viewport data.
183→    useEffect(() => {
184→        if (!userId) return;
185→        if (ownGalaxyLookupStartedRef.current) return;
186→
187→        ownGalaxyLookupStartedRef.current = true;
188→        let cancelled = false;
189→
190→        const resolveOwnGalaxyTarget = async () => {
191→            try {
192→                const { data, error } = await supabase
193→                    .from('galaxy_centroids')
194→                    .select('galaxy_x, galaxy_y')
195→                    .eq('user_id', userId)
196→                    .maybeSingle();
197→
198→                if (cancelled) return;
199→
200→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
201→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
202→                    setHasOwnPosts(true);
203→                    return;
204→                }
205→            } catch (err) {
206→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
207→            }
208→
209→            if (!cancelled) {
210→                setOwnGalaxyTarget(userHomeCoords(userId));
211→            }
212→        };
213→
214→        resolveOwnGalaxyTarget();
215→
216→        return () => {
217→            cancelled = true;
218→        };
219→    }, [userId]);
220→
221→    // Debounced fetch on camera/zoom change
222→    useEffect(() => {
223→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
224→
225→        fetchDebounceRef.current = setTimeout(async () => {
226→            const bounds = getViewportBounds();
227→            try {
228→                const result = await getUniversePosts(
229→                    bounds.minX,
230→                    bounds.maxX,
231→                    bounds.minY,
232→                    bounds.maxY,
233→                    200
234→                );
235→                if (result?.data) {
236→                    setPosts(prev => {
237→                        const next = new Map(prev);
238→                        for (const post of result.data) {
239→                            next.set(post.id, post);
240→                        }
241→                        return next;
242→                    });
243→                    if (userId && hasOwnPosts !== true) {
244→                        const ownsAny = result.data.some(p =>
245→                            (p.users?.id ?? p.user_id) === userId
246→                        );
247→                        if (ownsAny) setHasOwnPosts(true);
248→                    }
249→                }
250→                // Keep server gravity data as fallback when embeddings are absent in payload.
251→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
252→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
253→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
254→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
255→            } catch (err) {
256→                console.error('Failed to fetch universe posts:', err);
257→            } finally {
258→                if (!initialFetchResolvedRef.current) {
259→                    initialFetchResolvedRef.current = true;
260→                    setIsInitialLoading(false);
261→                }
262→            }
263→        }, 400);
264→
265→        return () => {
266→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
267→        };
268→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
269→
270→    const handleStarClick = useCallback((post) => {
271→        if (isFlying.current) return;
272→        setSelectedPost(post);
273→        setSelectedGalaxy(null);
274→        setGalaxyProfile(null);
275→
276→        const position = getComputedStarPosition(post);
277→        if (!position) return;
278→
279→        flyTo(position.x, position.y, 1.2, () => {
280→            setPulsingId(post.id);
281→            setTimeout(() => setPulsingId(null), 700);
282→        });
283→    }, [flyTo, getComputedStarPosition, isFlying]);
284→
285→    const handleGalaxyClick = useCallback(async (galaxy) => {
286→        if (isFlying.current) return;
287→        setSelectedGalaxy(galaxy);
288→        setSelectedPost(null);
289→        setGalaxyProfile(null);
290→        flyTo(galaxy.x, galaxy.y, 0.8);
291→
292→        try {
293→            const data = await getUserData(galaxy.userId);
294→            const profile = data?.userData?.[0] || null;
295→            setGalaxyProfile(profile);
296→        } catch (err) {
297→            console.error('Failed to fetch galaxy profile:', err);
298→        }
299→    }, [flyTo, isFlying]);
300→
301→    const handleReadPost = useCallback(() => {
302→        if (!selectedPost) return;
303→        navigate(`/home/post/${selectedPost.id}`);
304→    }, [selectedPost, navigate]);
305→
306→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
307→        if (mode === 'drag') {
308→            jumpTo(worldX, worldY);
309→            return;
310→        }
311→        flyTo(worldX, worldY, zoom);
312→    }, [flyTo, jumpTo, zoom]);
313→
314→    // One-time auto focus after first payload is loaded.
315→    useEffect(() => {
316→        if (!userId) return;
317→        if (isInitialLoading) return;
318→        if (hasAutoFocusedOwnGalaxyRef.current) return;
319→
320→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
321→        const target = ownGalaxy
322→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
323→            : (centroidTargets.get(userId) || ownGalaxyTarget);
324→
325→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
326→        if (!target) return;
327→
328→        hasAutoFocusedOwnGalaxyRef.current = true;
329→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
330→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
331→
332→    const settledPayload = useMemo(() => {
333→        if (!isSettled || activePosts.length === 0) return [];
334→
335→        const payload = [];
336→        for (const post of activePosts) {
337→            if (!post?.id) continue;
338→            const pos = getComputedStarPosition(post);
339→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
340→
341→            payload.push({
342→                post_id: post.id,
343→                settled_x: Math.round(pos.x * 100) / 100,
344→                settled_y: Math.round(pos.y * 100) / 100,
345→            });
346→        }
347→
348→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
349→        return payload;
350→    }, [activePosts, getComputedStarPosition, isSettled]);
351→
352→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
353→    useEffect(() => {
354→        if (!ENABLE_SETTLED_RPC_SAVE) return;
355→        if (!isSettled || settledPayload.length === 0) return;
356→
357→        const signature = JSON.stringify(settledPayload);
358→        if (signature === lastSettledPayloadRef.current) return;
359→
360→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
361→        settleDebounceRef.current = setTimeout(async () => {
362→            lastSettledPayloadRef.current = signature;
363→            try {
364→                const { error } = await supabase.rpc('save_universe_settled_positions', {
365→                    positions_payload: settledPayload,
366→                });
367→                if (error) {
368→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
369→                }
370→            } catch (err) {
371→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
372→            }
373→        }, 1200);
374→
375→        return () => {
376→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
377→        };
378→    }, [isSettled, settledPayload]);
379→
380→    useEffect(() => {
381→        return () => {
382→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
383→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
384→        };
385→    }, []);
386→
387→    return (
388→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
389→            <button className={styles.backButton} onClick={() => navigate('/home')}>
390→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
391→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
392→                </svg>
393→                Back
394→            </button>
395→
396→            <div className={styles.coordsLabel}>
397→                {centerWorld.x}, {centerWorld.y}
398→            </div>
399→
400→            {isInitialLoading && (
401→                <div className={styles.loadingOverlay}>
402→                    <div className={styles.loadingCard}>
403→                        <div className={styles.loadingSpinner} />
404→                        <div className={styles.loadingText}>Loading universe...</div>
405→                    </div>
406→                </div>
407→            )}
408→
409→            <Stage
410→                ref={stageRef}
411→                width={stageSize.width}
412→                height={stageSize.height}
413→                {...stageEvents}
414→            >
415→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
416→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
417→                <InteractiveLayer
418→                    layerProps={getLayerProps(1.0)}
419→                    posts={postArray}
420→                    galaxies={galaxies}
421→                    zoom={zoom}
422→                    showTitles={showTitles}
423→                    pulsingId={pulsingId}
424→                    onStarClick={handleStarClick}
425→                    onGalaxyClick={handleGalaxyClick}
426→                    galaxyPositions={galaxyPositions}
427→                    starPullOffsets={starPullOffsets}
428→                    similarPairs={similarPairs}
429→                    galaxyEdges={effectiveGalaxyEdges}
430→                    activePostIds={activePostIds}
431→                    useEmbeddingBridges={hasEmbeddingGravity}
432→                />
433→            </Stage>
434→
435→            <UniverseMinimap
436→                galaxies={galaxies}
437→                camera={camera}
438→                zoom={zoom}
439→                stageSize={stageSize}
440→                onNavigate={handleMinimapNavigate}
441→            />
442→
443→            {selectedGalaxy && galaxyProfile && (
444→                <div className={styles.galaxyPreviewPanel}>
445→                    <button
446→                        className={styles.galaxyPreviewClose}
447→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
448→                    >
449→                        &times;
450→                    </button>
451→                    <div
452→                        className={styles.galaxyPreviewBg}
453→                        style={galaxyProfile.background || {}}
454→                    />
455→                    <div className={styles.galaxyPreviewContent}>
456→                        <img
457→                            className={styles.galaxyPreviewAvatar}
458→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
459→                            alt=""
460→                        />
461→                        <div className={styles.galaxyPreviewHeading}>
462→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
463→                        </div>
464→                        {galaxyProfile.bio && (
465→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
466→                        )}
467→                        <button
468→                            className={styles.galaxyPreviewVisitBtn}
469→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
470→                        >
471→                            Visit Profile
472→                        </button>
473→                    </div>
474→                </div>
475→            )}
476→
477→            {selectedPost && (
478→                <div className={styles.previewPanel}>
479→                    <button
480→                        className={styles.previewClose}
481→                        onClick={() => setSelectedPost(null)}
482→                    >
483→                        &times;
484→                    </button>
485→                    <div className={styles.previewAuthor}>
486→                        <img
487→                            className={styles.previewAvatar}
488→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
489→                            alt=""
490→                        />
491→                        <span className={styles.previewAuthorName}>
492→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
493→                        </span>
494→                    </div>
495→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
496→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
497→                    <div className={styles.previewLikes}>
498→                        {(() => {
499→                            const count = selectedPost.like_count != null
500→                                ? selectedPost.like_count
501→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
502→                                    ? selectedPost.likes[0].count : 0);
503→                            return `${count} like${count !== 1 ? 's' : ''}`;
504→                        })()}
505→                    </div>
506→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
507→                        Read
508→                    </button>
509→                </div>
510→            )}
511→        </div>
512→    );
513→};
514→
515→export default Universe;
